SELECT COUNT(1) cishu,SUM(oxyKcal) oxyKcal,SUM(unoxyKcal) unoxyKcal,SUM(sportStep) sportStep,
SUM(distance) distance,(SELECT SEC_TO_TIME(SUM(TIME_TO_SEC(`sportTime`)))) sumST,
(SELECT SEC_TO_TIME(SUM(TIME_TO_SEC(`sportTime`)))) sportTime,SUM(energy) energy,YEAR(createdDate) data
FROM sport_active WHERE userId= #{userId} AND sportType = #{sportType}
GROUP BY YEAR(createdDate) ORDER BY YEAR(createdDate) DESC;

