update sport_record
 set privateClassCount = privateClassCount + 1,
     privateClassKcal = ifnull(privateClassKcal,0) + #{energy,jdbcType=DOUBLE}
     where userId = #{studentId,jdbcType=BIGINT}

update sport_record
set teamClassCount = teamClassCount + 1,
teamClassKcal = ifnull(teamClassKcal,0) + #{energy,jdbcType=DOUBLE}
where userId = #{studentId,jdbcType=BIGINT}
